--
-- Name: __master_data_vulnerability_descriptions_read_model; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.__master_data_vulnerability_descriptions_read_model AS
 SELECT vd.legacy_id AS legacyid,
    vd.title,
    vd.cvss2_base_score AS cvssbase,
    vd.cvss2_temporal_score AS cvsstemporal,
    vd.how_to_fix AS howtofix,
    COALESCE(vd.description, ''::text) AS description,
        CASE
            WHEN (((vd.cvss2_base_vector)::text = ''::text) IS FALSE) THEN (('('::text || (vd.cvss2_base_vector)::text) || ')'::text)
            ELSE '-'::text
        END AS cvssbasedescription,
        CASE
            WHEN (((vd.cvss2_temporal_vector)::text = ''::text) IS FALSE) THEN (('('::text || (vd.cvss2_temporal_vector)::text) || ')'::text)
            ELSE '-'::text
        END AS cvsstemporaldescription,
    COALESCE(vi.cvss, ''::text) AS cvelist
   FROM (public.__master_data_vulnerability_definitions vd
     LEFT JOIN ( SELECT vi_1.vulnerability_id,
            array_to_string(array_agg(vi_1.value), ','::text) AS cvss
           FROM public.__master_data_vulnerability_identifiers vi_1
          WHERE ((vi_1.type)::text = 'CVE'::text)
          GROUP BY vi_1.vulnerability_id) vi ON ((vd.id = vi.vulnerability_id)))
UNION ALL
 SELECT bd.legacy_id AS legacyid,
    bd.title,
    bd.cvss2_base_score AS cvssbase,
    bd.cvss2_temporal_score AS cvsstemporal,
    bd.how_to_fix AS howtofix,
    COALESCE(bd.description, ''::text) AS description,
    bd.cvss2_base_vector AS cvssbasedescription,
    bd.cvss2_temporal_vector AS cvsstemporaldescription,
    ''::text AS cvelist
   FROM public.__master_data_bulletin_definitions bd
  WITH NO DATA;


