--
-- Name: __requirement_custom_instructions; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.__requirement_custom_instructions AS
 WITH RECURSIVE requirement_instructions AS (
         SELECT r.requirement_id,
            r.binding_model_type_id
           FROM public.__requirements r
        UNION
         SELECT t.requirement_id,
            i.child_id
           FROM (public.__type_inheritance i
             JOIN requirement_instructions t ON ((i.type_id = t.binding_model_type_id)))
        ), custom_instructions AS (
         SELECT r.requirement_id,
            rc.check_id,
            rcci.check_verdict_type,
            rcci.type_id,
            rcci.locale,
            rcci.instruction
           FROM ((public.__requirements r
             JOIN public.__requirement_checks rc ON ((r.requirement_id = rc.requirement_id)))
             JOIN public.__requirement_check_custom_instructions_l10ns rcci ON (((r.requirement_id = rcci.requirement_id) AND (rc.check_id = rcci.check_id))))
        UNION
         SELECT i.requirement_id,
            i.check_id,
            i.check_verdict_type,
            n.child_id,
            i.locale,
            i.instruction
           FROM (custom_instructions i
             JOIN public.__type_inheritance n ON ((n.type_id = i.type_id)))
        )
 SELECT r.requirement_id,
    rc.check_id,
    NULL::integer AS binding_model_type_id,
    rcfi.check_verdict_type,
    rcfi.locale,
    rcfi.instruction
   FROM ((public.__requirements r
     JOIN public.__requirement_checks rc ON ((r.requirement_id = rc.requirement_id)))
     JOIN public.__requirement_check_fail_info_l10ns rcfi ON (((r.requirement_id = rcfi.requirement_id) AND (rc.check_id = rcfi.check_id))))
UNION
 SELECT r.requirement_id,
    rc.check_id,
    r.binding_model_type_id,
    COALESCE(ci.check_verdict_type, rcfi.check_verdict_type) AS check_verdict_type,
    COALESCE(ci.locale, rcfi.locale) AS locale,
    COALESCE(ci.instruction, rcfi.instruction) AS instruction
   FROM (((requirement_instructions r
     JOIN public.__requirement_checks rc ON ((r.requirement_id = rc.requirement_id)))
     JOIN public.__requirement_check_fail_info_l10ns rcfi ON (((r.requirement_id = rcfi.requirement_id) AND (rc.check_id = rcfi.check_id))))
     LEFT JOIN custom_instructions ci ON (((r.requirement_id = ci.requirement_id) AND (rc.check_id = ci.check_id) AND (r.binding_model_type_id = ci.type_id) AND (rcfi.check_verdict_type = ci.check_verdict_type))))
  WITH NO DATA;


