--
-- Name: __vulner_components_read_model; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.__vulner_components_read_model AS
 WITH vulner_sets AS (
         SELECT DISTINCT vc.vulnerability_id,
            cs.id AS condition_set_id
           FROM ((public.__master_data_vulnerability_existence_conditions vc
             JOIN public.__master_data_existence_conditions ec ON ((ec.id = vc.existence_condition_id)))
             JOIN public.__master_data_condition_sets cs ON ((cs.id = ec.component_set_id)))
        ), bulletin_sets AS (
         SELECT DISTINCT brv.vulnerability_id,
            cs.id AS condition_set_id
           FROM (((public.__master_data_bulletin_related_vulners brv
             JOIN public.__master_data_bulletin_existence_conditions bc ON ((bc.bulletin_id = brv.bulletin_id)))
             JOIN public.__master_data_existence_conditions ec ON ((ec.id = bc.existence_condition_id)))
             JOIN public.__master_data_condition_sets cs ON ((cs.id = ec.component_set_id)))
        ), condition_sets AS (
         SELECT vulner_sets.vulnerability_id,
            vulner_sets.condition_set_id
           FROM vulner_sets
        UNION
         SELECT bulletin_sets.vulnerability_id,
            bulletin_sets.condition_set_id
           FROM bulletin_sets
        ), discrete_product_dimension_conditions AS (
         SELECT cs.vulnerability_id,
            dc.dimension_id
           FROM (condition_sets cs
             JOIN public.__master_data_discrete_product_dimension_conditions dc ON ((dc.set_id = cs.condition_set_id)))
        ), interval_product_dimension_condition AS (
         SELECT cs.vulnerability_id,
            dc.dimension_id
           FROM (condition_sets cs
             JOIN public.__master_data_interval_product_dimension_conditions dc ON ((dc.set_id = cs.condition_set_id)))
        ), excluded_interval_product_dimension_condition AS (
         SELECT cs.vulnerability_id,
            dc.dimension_id
           FROM (condition_sets cs
             JOIN public.__master_data_excluded_interval_product_dimension_conditions dc ON ((dc.set_id = cs.condition_set_id)))
        ), pattern_product_dimension_condition AS (
         SELECT cs.vulnerability_id,
            dc.dimension_id
           FROM (condition_sets cs
             JOIN public.__master_data_pattern_product_dimension_conditions dc ON ((dc.set_id = cs.condition_set_id)))
        ), product_condition AS (
         SELECT DISTINCT cs.vulnerability_id,
            dc.product_id
           FROM (condition_sets cs
             JOIN public.__master_data_product_conditions dc ON ((dc.set_id = cs.condition_set_id)))
        ), vulner_dumensions AS (
         SELECT discrete_product_dimension_conditions.vulnerability_id,
            discrete_product_dimension_conditions.dimension_id
           FROM discrete_product_dimension_conditions
        UNION
         SELECT interval_product_dimension_condition.vulnerability_id,
            interval_product_dimension_condition.dimension_id
           FROM interval_product_dimension_condition
        UNION
         SELECT excluded_interval_product_dimension_condition.vulnerability_id,
            excluded_interval_product_dimension_condition.dimension_id
           FROM excluded_interval_product_dimension_condition
        UNION
         SELECT pattern_product_dimension_condition.vulnerability_id,
            pattern_product_dimension_condition.dimension_id
           FROM pattern_product_dimension_condition
        ), vulner_dimension_products AS (
         SELECT DISTINCT vd.vulnerability_id,
            pd.product_id
           FROM (vulner_dumensions vd
             JOIN public.__master_data_product_dimensions pd ON ((pd.id = vd.dimension_id)))
        ), vulner_products AS (
         SELECT vulner_dimension_products.vulnerability_id,
            vulner_dimension_products.product_id
           FROM vulner_dimension_products
        UNION
         SELECT pc.vulnerability_id,
            pc.product_id
           FROM product_condition pc
        )
 SELECT DISTINCT v.external_id AS vulner_id,
    v.legacy_id,
    p.id AS product_id,
    p.name AS product_name,
    p.vendor AS vendor_name,
    (lower((p.model_entity_name)::text) IN ( SELECT __network_check_types.type_name
           FROM public.__network_check_types)) AS is_pentest_check
   FROM ((public.__master_data_vulnerability_definitions v
     JOIN vulner_products vp ON ((v.id = vp.vulnerability_id)))
     JOIN public.__master_data_products p ON ((vp.product_id = p.id)))
  WHERE (v.is_removed = false)
  WITH NO DATA;


--
-- Name: __vulner_impact_read_model; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.__vulner_impact_read_model AS
 SELECT legacy_id,
    unnest(impacts) AS impact_type
   FROM public.__master_data_vulnerability_definitions vd
  WHERE (is_removed = false)
  WITH NO DATA;


--
-- Name: __vulner_info_read_model; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.__vulner_info_read_model AS
 SELECT external_id AS vulner_id,
    legacy_id,
    type,
    title AS name,
    description,
    short_description,
    cvss2_base_vector,
    cvss2_base_score,
    cvss2_temporal_vector,
    cvss2_temporal_score,
    cvss3_base_vector,
    cvss3_base_score,
    cvss3_temporal_vector,
    cvss3_temporal_score,
    how_to_fix,
    level,
    issue_date AS issue_time,
    is_trend,
    is_trend_since,
    (EXISTS ( SELECT 1
           FROM public.__vulner_components_read_model vc
          WHERE (((vc.vulner_id)::text = (v.external_id)::text) AND vc.is_pentest_check))) AS has_pentest_check,
        CASE
            WHEN (cvss3_base_vector IS NOT NULL) THEN (((cvss3_base_vector)::text ~ 'AV:N'::text) OR ((cvss3_base_vector)::text ~ 'AV:A'::text))
            WHEN (cvss2_base_vector IS NOT NULL) THEN (((cvss2_base_vector)::text ~ 'AV:N'::text) OR ((cvss2_base_vector)::text ~ 'AV:A'::text))
            ELSE false
        END AS has_network_attack_vector,
        CASE
            WHEN (cvss3_temporal_vector IS NOT NULL) THEN (((cvss3_temporal_vector)::text ~ 'E:F'::text) OR ((cvss3_temporal_vector)::text ~ 'E:H'::text))
            WHEN (cvss2_temporal_vector IS NOT NULL) THEN (((cvss2_temporal_vector)::text ~ 'E:F'::text) OR ((cvss2_temporal_vector)::text ~ 'E:H'::text))
            ELSE false
        END AS is_exploitable,
        CASE
            WHEN (cvss3_temporal_vector IS NOT NULL) THEN (((cvss3_temporal_vector)::text ~ 'RL:O'::text) OR ((cvss3_temporal_vector)::text ~ 'RL:T'::text))
            WHEN (cvss2_temporal_vector IS NOT NULL) THEN (((cvss2_temporal_vector)::text ~ 'RL:OF'::text) OR ((cvss2_temporal_vector)::text ~ 'RL:TF'::text))
            ELSE false
        END AS has_fix,
    COALESCE(impacts, ARRAY[NULL::character varying]) AS impact_types,
        CASE
            WHEN ('RCE'::text = ANY ((impacts)::text[])) THEN 'RCE'::text
            WHEN ('LPE'::text = ANY ((impacts)::text[])) THEN 'LPE'::text
            WHEN ('DoS'::text = ANY ((impacts)::text[])) THEN 'DoS'::text
            ELSE NULL::text
        END AS primary_impact_type,
    package_id
   FROM public.__master_data_vulnerability_definitions v
  WHERE (is_removed = false)
  WITH NO DATA;


--
-- Name: __vulner_key_read_model; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.__vulner_key_read_model AS
 SELECT lower((vi.type)::text) AS class_name,
        CASE
            WHEN ((lower((vi.type)::text) = 'cve'::text) OR (lower((vi.type)::text) = 'bdu'::text)) THEN (vi.value)::text
            ELSE ((upper((vi.type)::text) || '-'::text) || (vi.value)::text)
        END AS class_value,
    vd.external_id AS vulner_id,
    vd.legacy_id,
    vi.uri
   FROM (public.__master_data_vulnerability_definitions vd
     JOIN public.__master_data_vulnerability_identifiers vi ON ((vi.vulnerability_id = vd.id)))
  WHERE ((vd.is_removed = false) AND (vi.value IS NOT NULL))
  WITH NO DATA;


--
-- Name: __vulner_keys_array_read_model; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.__vulner_keys_array_read_model AS
 SELECT COALESCE(array_agg(class_value) FILTER (WHERE (class_name = 'cve'::text)), (ARRAY[NULL::character varying])::text[]) AS all_cve,
    COALESCE(array_agg(uri) FILTER (WHERE (class_name = 'cve'::text)), ARRAY[NULL::character varying]) AS all_cve_url,
    COALESCE(array_agg(class_value) FILTER (WHERE (class_name <> 'ptkb'::text)), (ARRAY[NULL::character varying])::text[]) AS all_id,
    COALESCE(array_agg(uri) FILTER (WHERE (class_name <> 'ptkb'::text)), ARRAY[NULL::character varying]) AS all_id_url,
    COALESCE(array_agg((json_build_object('displayName', class_value, 'url', uri))::jsonb) FILTER (WHERE (class_name = 'cve'::text)), ARRAY[NULL::jsonb]) AS all_cve_hyperlink,
    COALESCE(array_agg((json_build_object('displayName', class_value, 'url', uri))::jsonb) FILTER (WHERE (class_name <> 'ptkb'::text)), ARRAY[NULL::jsonb]) AS all_id_hyperlink,
    legacy_id
   FROM public.__vulner_key_read_model
  GROUP BY legacy_id
  WITH NO DATA;


--
-- Name: __vulner_links_read_model; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.__vulner_links_read_model AS
 SELECT vd.external_id AS vulner_id,
    vd.legacy_id,
    unnest(vd.links) AS link_url
   FROM public.__master_data_vulnerability_definitions vd
  WHERE (vd.is_removed = false)
UNION ALL
 SELECT bd.external_id AS vulner_id,
    bd.legacy_id,
    unnest(bd.links) AS link_url
   FROM public.__master_data_bulletin_definitions bd
  WHERE (bd.is_removed = false)
  WITH NO DATA;


--
-- Name: __vulner_links_array_read_model; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.__vulner_links_array_read_model AS
 SELECT COALESCE(array_agg(link_url), ARRAY[NULL::character varying]) AS all_links,
    COALESCE(array_agg((json_build_object('displayName', link_url, 'url', link_url))::jsonb), ARRAY[NULL::jsonb]) AS all_links_hyperlink,
    legacy_id
   FROM public.__vulner_links_read_model
  GROUP BY legacy_id
  WITH NO DATA;


--
-- Name: __vulner_passport_qsearch; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.__vulner_passport_qsearch AS
 SELECT vd.external_id AS vulner_id,
    vd.legacy_id,
    lower((((((vd.title)::text || '•'::text) || vd.description) || '•'::text) || array_to_string(array_agg(vkrm.class_value), '•'::text))) AS search_text
   FROM (public.__master_data_vulnerability_definitions vd
     LEFT JOIN public.__vulner_key_read_model vkrm ON (((vkrm.vulner_id)::text = (vd.external_id)::text)))
  WHERE (vd.is_removed = false)
  GROUP BY vd.external_id, vd.legacy_id, vd.title, vd.description
  WITH NO DATA;


